31	class CoreMiniAxiWrapper {
32	 public:
33	  explicit CoreMiniAxiWrapper(VerilatedContext* context)
34	      : context_(context),
35	        core_(context, "core"),
36	        clock_(context, &core_.io_aclk, &core_),
37	        slave_write_driver_(&clock_, &core_.io_axi_slave_write_addr_valid,
38	                            &core_.io_axi_slave_write_addr_bits_addr,
39	                            &core_.io_axi_slave_write_addr_bits_prot,
40	                            &core_.io_axi_slave_write_addr_bits_id,
41	                            &core_.io_axi_slave_write_addr_bits_len,
42	                            &core_.io_axi_slave_write_addr_bits_size,
43	                            &core_.io_axi_slave_write_addr_bits_burst,
44	                            &core_.io_axi_slave_write_addr_bits_lock,
45	                            &core_.io_axi_slave_write_addr_bits_cache,
46	                            &core_.io_axi_slave_write_addr_bits_qos,
47	                            &core_.io_axi_slave_write_addr_bits_region,
48	                            &core_.io_axi_slave_write_addr_ready,
49	                            &core_.io_axi_slave_write_data_valid,
50	                            &core_.io_axi_slave_write_data_bits_data,
51	                            &core_.io_axi_slave_write_data_bits_strb,
52	                            &core_.io_axi_slave_write_data_bits_last,
53	                            &core_.io_axi_slave_write_data_ready,
54	                            &core_.io_axi_slave_write_resp_valid,
55	                            &core_.io_axi_slave_write_resp_bits_id,
56	                            &core_.io_axi_slave_write_resp_bits_resp,
57	                            &core_.io_axi_slave_write_resp_ready),
58	        slave_read_driver_(&clock_, &core_.io_axi_slave_read_addr_valid,
59	                           &core_.io_axi_slave_read_addr_bits_addr,
60	                           &core_.io_axi_slave_read_addr_bits_prot,
61	                           &core_.io_axi_slave_read_addr_bits_id,
62	                           &core_.io_axi_slave_read_addr_bits_len,
63	                           &core_.io_axi_slave_read_addr_bits_size,
64	                           &core_.io_axi_slave_read_addr_bits_burst,
65	                           &core_.io_axi_slave_read_addr_bits_lock,
66	                           &core_.io_axi_slave_read_addr_bits_cache,
67	                           &core_.io_axi_slave_read_addr_bits_qos,
68	                           &core_.io_axi_slave_read_addr_bits_region,
69	                           &core_.io_axi_slave_read_addr_ready,
70	                           &core_.io_axi_slave_read_data_valid,
71	                           &core_.io_axi_slave_read_data_bits_data,
72	                           &core_.io_axi_slave_read_data_bits_id,
73	                           &core_.io_axi_slave_read_data_bits_resp,
74	                           &core_.io_axi_slave_read_data_bits_last,
75	                           &core_.io_axi_slave_read_data_ready),
76	        master_read_driver_(&clock_, &core_.io_axi_master_read_addr_valid,
77	                            &core_.io_axi_master_read_addr_bits_addr,
78	                            &core_.io_axi_master_read_addr_bits_prot,
79	                            &core_.io_axi_master_read_addr_bits_id,
80	                            &core_.io_axi_master_read_addr_bits_len,
81	                            &core_.io_axi_master_read_addr_bits_size,
82	                            &core_.io_axi_master_read_addr_bits_burst,
83	                            &core_.io_axi_master_read_addr_bits_lock,
84	                            &core_.io_axi_master_read_addr_bits_cache,
85	                            &core_.io_axi_master_read_addr_bits_qos,
86	                            &core_.io_axi_master_read_addr_bits_region,
87	                            &core_.io_axi_master_read_addr_ready,
88	                            &core_.io_axi_master_read_data_valid,
89	                            &core_.io_axi_master_read_data_bits_data,
90	                            &core_.io_axi_master_read_data_bits_id,
91	                            &core_.io_axi_master_read_data_bits_resp,
92	                            &core_.io_axi_master_read_data_bits_last,
93	                            &core_.io_axi_master_read_data_ready),
94	        master_write_driver_(&clock_, &core_.io_axi_master_write_addr_valid,
95	                             &core_.io_axi_master_write_addr_bits_addr,
96	                             &core_.io_axi_master_write_addr_bits_prot,
97	                             &core_.io_axi_master_write_addr_bits_id,
98	                             &core_.io_axi_master_write_addr_bits_len,
99	                             &core_.io_axi_master_write_addr_bits_size,
100	                             &core_.io_axi_master_write_addr_bits_burst,
101	                             &core_.io_axi_master_write_addr_bits_lock,
102	                             &core_.io_axi_master_write_addr_bits_cache,
103	                             &core_.io_axi_master_write_addr_bits_qos,
104	                             &core_.io_axi_master_write_addr_bits_region,
105	                             &core_.io_axi_master_write_addr_ready,
106	                             &core_.io_axi_master_write_data_valid,
107	                             &core_.io_axi_master_write_data_bits_data,
108	                             &core_.io_axi_master_write_data_bits_strb,
109	                             &core_.io_axi_master_write_data_bits_last,
110	                             &core_.io_axi_master_write_data_ready,
111	                             &core_.io_axi_master_write_resp_valid,
112	                             &core_.io_axi_master_write_resp_bits_id,
113	                             &core_.io_axi_master_write_resp_bits_resp,
114	                             &core_.io_axi_master_write_resp_ready),
115	        halted_(&core_.io_halted),
116	        wfi_(&core_.io_wfi) {}
117	  ~CoreMiniAxiWrapper() = default;
118	
119	  void Reset() {
120	    core_.io_aresetn = 1;
121	    context_->timeInc(1);
122	    core_.io_aresetn = 0;
123	    context_->timeInc(1);
124	    core_.io_aresetn = 1;
125	    context_->timeInc(1);
126	  }
127	
128	  void Step() { clock_.Step(); }
129	
130	  CoralNPUMailbox& mailbox() { return mailbox_; }
131	
132	  const CoralNPUMailbox& mailbox() const { return mailbox_; }
133	
134	  const CoralNPUMailbox& ReadMailbox(void) { return mailbox_; }
135	
136	  void WriteMailbox(const CoralNPUMailbox& mailbox) {
137	    for (int i = 0; i < 4; i++) {
138	      mailbox_.message[i] = mailbox.message[i];
139	    }
140	  }
141	
142	  void Write(uint32_t addr, uint32_t len, const char* data) {
143	    auto write_data =
144	        absl::Span<const uint8_t>(reinterpret_cast<const uint8_t*>(data), len);
145	    while (write_data.size() > 0) {
146	      uint32_t offset4096 = addr % 4096;
147	      uint32_t remainder4096 = 4096 - offset4096;
148	      uint32_t max_transaction_bytes = std::min(4096u, remainder4096);
149	      uint32_t transaction_bytes = std::min(
150	          static_cast<uint32_t>(write_data.size()), max_transaction_bytes);
151	      absl::Span<const uint8_t> local_data =
152	          write_data.subspan(0, transaction_bytes);
153	
154	      std::shared_ptr<bool> transaction =
155	          slave_write_driver_.WriteTransaction(0, addr, local_data);
156	      while (!(*transaction)) {
157	        Step();
158	      }
159	
160	      write_data.remove_prefix(transaction_bytes);
161	      addr += transaction_bytes;
162	    }
163	  }
164	
165	  std::vector<uint8_t> Read(uint32_t addr, uint32_t len) {
166	    std::vector<uint8_t> result;
167	    result.reserve(len);
168	    while (result.size() < len) {
169	      uint32_t offset4096 = addr % 4096;
170	      uint32_t remainder4096 = 4096 - offset4096;
171	      uint32_t max_transaction_bytes = std::min(4096u, remainder4096);
172	      uint32_t bytes_remaining = len - result.size();
173	      uint32_t transaction_bytes = std::min(
174	          static_cast<uint32_t>(bytes_remaining), max_transaction_bytes);
175	
176	      auto transaction =
177	          slave_read_driver_.ReadTransaction(0, addr, transaction_bytes);
178	      while (!(transaction->finished)) {
179	        Step();
180	      }
181	      std::copy(transaction->data.begin(), transaction->data.end(),
182	                std::back_inserter(result));
183	
184	      addr += transaction_bytes;
185	    }
