29	struct BackdoorSram {
30	  std::vector<uint8_t> data;
31	  uint64_t global_addr;
32	  uint32_t width_bytes;
33	};
34	
35	std::map<uint64_t, BackdoorSram *> registered_srams;
36	
37	bool ApplyLoadToSram(BackdoorSram &sram, uint64_t load_addr,
38	                     const uint8_t *data, size_t len) {
39	  uint64_t load_end = load_addr + len;
40	  uint64_t sram_end = sram.global_addr + sram.data.size();
41	
42	  if (load_end <= sram.global_addr || load_addr >= sram_end) {
43	    return false;
44	  }
45	
46	  uint64_t start = std::max(load_addr, sram.global_addr);
47	  uint64_t end = std::min(load_end, sram_end);
48	  uint64_t copy_len = end - start;
49	  uint64_t sram_offset = start - sram.global_addr;
50	  uint64_t data_offset = start - load_addr;
51	
52	  std::memcpy(sram.data.data() + sram_offset, data + data_offset, copy_len);
53	  return true;
54	}
55	
56	void *RegisterSram(uint64_t global_addr, size_t size_bytes,
57	                   uint32_t width_bytes) {
58	  BackdoorSram *sram = new BackdoorSram;
59	  sram->global_addr = global_addr;
60	  sram->data.resize(size_bytes);
61	  sram->width_bytes = width_bytes;
62	
63	  // Randomize memory content for simulation.
64	  std::random_device rd;
65	  std::mt19937 gen(rd());
66	  std::uniform_int_distribution<> dis(0, 255);
67	  for (size_t i = 0; i < size_bytes; ++i) {
68	    sram->data[i] = dis(gen);
69	  }
70	
71	  registered_srams[global_addr] = sram;
72	
73	  return sram;
74	}
